  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index) VALUES
    (v_sop_id, 1, 'Objetivo', E'Produzir propostas comerciais que convertem — claras, bem precificadas, visualmente impecáveis e alinhadas à expectativa do cliente. Meta: taxa de conversão proposta→contrato ≥ 50%.', 'step', 0),
    (v_sop_id, 2, 'Escopo e RACI', E'**Responsável:** Ruy Lima (elaboração e envio). Marco Andolfato revisa escopo e precificação em projetos complexos.\n\n| Atividade | Responsável | Aprovador |\n|---|---|---|\n| Coletar briefing preliminar | Ruy Lima | — |\n| Definir escopo técnico | Ruy + Líder BU | Marco |\n| Precificar projeto | Ruy Lima | Marco |\n| Redigir e formatar proposta | Ruy Lima | Marco |\n| Apresentar ao cliente | Ruy Lima | — |\n| Follow-up estruturado | Ruy Lima | — |', 'step', 1),
    (v_sop_id, 3, 'Estrutura Obrigatória da Proposta', E'1. Capa (logo TBO + cliente + empreendimento + data)\n2. Sobre a TBO (posicionamento + cases + números)\n3. Entendimento do projeto (o que o cliente precisa)\n4. Nossa proposta (solução estratégica e criativa)\n5. Escopo detalhado por BU (especificações + limites)\n6. Timeline (cronograma visual com marcos)\n7. Investimento (valores + condições de pagamento)\n8. Portfólio (3+ cases similares ao projeto)\n9. Próximos passos\n10. Contato (Ruy Lima)', 'step', 2),
    (v_sop_id, 4, 'Precificação', E'1. Calcular custo base: horas estimadas × custo/hora por BU\n2. Aplicar margem mínima de 40%\n3. Ajustes de contexto:\n   - Cliente estratégico: desconto ≤ 15% (aprovação Marco)\n   - Prazo urgente (< 50% do padrão): +25-50%\n4. Parcelas padrão: 50% na assinatura + 50% na entrega\n   - Projetos > R$150k: 40% + 30% + 30%\n5. Registrar valor proposto no CRM antes de enviar', 'step', 3),
    (v_sop_id, 5, 'Follow-up Estruturado', E'| Dia | Ação | Canal |\n|---|---|---|\n| D+0 (envio) | Confirmar recebimento | WhatsApp |\n| D+2 | "Tiveram chance de avaliar?" | WhatsApp |\n| D+5 | "Alguma dúvida sobre o escopo?" | E-mail |\n| D+10 | Ligação direta | Telefone |\n| D+15 | Última mensagem + data de validade | E-mail |\n| D+20 | Arquivar como perdido ou renegociar | CRM |', 'step', 4),
    (v_sop_id, 6, 'Checklist de Validação', E'**Antes de enviar:**\n- [ ] Escopo com especificações claras e limites definidos\n- [ ] Precificação validada com Marco\n- [ ] Timeline realista (validado com líderes BU)\n- [ ] Mínimo 3 cases similares no portfólio incluídos\n- [ ] PDF exportado em alta resolução com nome correto\n- [ ] Deal atualizado no CRM com valor e data\n\n**Após envio:**\n- [ ] Follow-up D+2 agendado no calendário\n- [ ] Próxima ação registrada no CRM com data', 'checkpoint', 5),
    (v_sop_id, 7, 'SLAs e Métricas', E'| Métrica | Meta |\n|---|---|\n| Envio de proposta após briefing | ≤ 3 dias úteis |\n| Follow-up após envio | D+2 (obrigatório) |\n| Taxa de conversão proposta→contrato | ≥ 50% |\n| Tempo médio de decisão do cliente | ≤ 15 dias |\n| Propostas sem registro no CRM | 0% |', 'note', 6),
    (v_sop_id, 8, 'Troubleshooting', E'**Cliente some após receber a proposta:**\n→ Seguir cronograma de follow-up. Na mensagem D+10: "Estou reservando a capacidade da equipe para o projeto [nome]. Preciso saber se seguimos para poder abrir agenda."\n\n**Cliente pede desconto agressivo:**\n→ Nunca desconto sem contrapartida: "Posso ajustar se reduzirmos o escopo em [X]"\n→ Desconto > 10% requer aprovação de Marco\n\n**Erro de precificação na proposta enviada:**\n→ Contatar o cliente imediatamente, assumir o erro, enviar versão corrigida\n→ NUNCA honrar precificação com margem negativa', 'warning', 7),
    (v_sop_id, 9, 'Template: E-mail de Envio', E'```\nAssunto: Proposta TBO — [Nome Empreendimento] | [Mês/Ano]\n\nOlá [Nome],\n\nFoi ótimo conversar sobre o [Nome Empreendimento]. Segue nossa proposta em anexo.\n\nDestaques:\n• [Destaque 1 — entregável mais estratégico]\n• [Destaque 2 — diferencial da abordagem TBO]\n• [Destaque 3 — prazo ou resultado esperado]\n\nA proposta tem validade de 30 dias. Se quiserem 20 minutos para alinhar qualquer detalhe, é só responder este e-mail.\n\nAbraços,\nRuy Lima | Diretor Comercial | TBO\n```', 'tip', 8);

  -- ══════════════════════════════════════════════════════════════════════════
  -- MELHORIA 3: RH — Avaliação de Performance e Desenvolvimento
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Avaliação de Performance e Desenvolvimento',
    'tbo-rh-003-avaliacao-de-performance-e-desenvolvimento',
    'recursos-humanos',
    'processo',
    'Processo de avaliação de performance trimestral da TBO, incluindo autoavaliação, avaliação 360°, feedback estruturado e conexão com PDI (Plano de Desenvolvimento Individual). Define critérios, escalas, rituais e ações pós-avaliação.',
    E'## Avaliação de Performance e Desenvolvimento\n\n### 1. Objetivo\nGerar crescimento real — não só medir. A avaliação de performance na TBO não é burocracia: é o principal mecanismo de desenvolvimento das pessoas e de manutenção de um time de alta performance. Cada ciclo de avaliação deve resultar em 1 ação concreta de desenvolvimento por colaborador. Meta: 100% do time avaliado trimestralmente, 0% de avaliações sem PDI atualizado.\n\n### 2. Escopo\n**Quem executa:** Marco Andolfato e Ruy Lima (conduzem avaliações de líderes de BU) + Líderes de BU (conduzem avaliações dos colaboradores de suas equipes)\n**Quando se aplica:** Ciclo trimestral (março, junho, setembro, dezembro). Novos colaboradores: avaliação ao fim do 3º mês (período de experiência).\n**Limites:** Contratação → SOP tbo-rh-001. Onboarding → SOP tbo-rh-002. PDI detalhado → SOP tbo-rh-005. Desligamento → SOP tbo-rh-004.\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Disparar ciclo de avaliação | Marco Andolfato | — | — | Todos |\n| Preencher autoavaliação | Colaborador | — | — | Líder BU |\n| Preencher avaliação do gestor | Líder BU | — | — | Marco/Ruy |\n| Consolidar avaliação 360° | Marco Andolfato | — | Líder BU | — |\n| Conduzir reunião de feedback 1:1 | Líder BU (com colaborador) | — | — | Marco |\n| Atualizar PDI no TBO OS | Colaborador + Líder BU | Marco (líderes) | — | — |\n| Tomar decisões salariais/promoção | Marco Andolfato + Ruy Lima | — | Líderes BU | Colaborador |\n| Documentar e arquivar avaliações | Marco Andolfato | — | — | — |\n\n### 4. Pré-requisitos\n\n- [ ] Calendário do ciclo de avaliação comunicado com 2 semanas de antecedência\n- [ ] Formulário de avaliação disponível no TBO OS (ou Google Forms)\n- [ ] PDI anterior consultado (para verificar evolução)\n- [ ] Gestor preparou exemplos concretos de comportamentos observados\n- [ ] Bloco de 45-60 min reservado na agenda para o 1:1 de feedback\n\n### 5. Procedimento\n\n**5.1 Semana 1 — Autoavaliação e Avaliação do Gestor (assíncrono)**\n\nO colaborador preenche a autoavaliação. Simultaneamente, o gestor preenche sua avaliação. Ambos sem ver a resposta do outro.\n\n**Critérios de avaliação (escala 1-5):**\n\n| Critério | Peso | Descrição |\n|---|---|---|\n| Qualidade de entrega | 25% | Precisão, capricho, alinhamento ao briefing |\n| Produtividade e prazo | 20% | Entregas dentro do prazo sem comprometer qualidade |\n| Autonomia e proatividade | 15% | Resolve sem precisar ser acionado |\n| Colaboração e comunicação | 15% | Trabalha bem em time, comunica bloqueios cedo |\n| Aprendizado e crescimento | 15% | Busca melhorar, absorve feedbacks anteriores |\n| Alinhamento cultural | 10% | Vive os valores da TBO (excelência, honestidade, criatividade) |\n\n**Escala:**\n- **5 — Supera**: consistentemente entrega acima do esperado\n- **4 — Atende com destaque**: atende e frequentemente supera\n- **3 — Atende**: entrega o que é esperado\n- **2 — Em desenvolvimento**: atende parcialmente, precisa de suporte\n- **1 — Abaixo**: não atende, requer intervenção urgente\n\n**5.2 Semana 1 — Avaliação 360° (pares)**\n\nCada colaborador recebe 2-3 avaliações de colegas com quem trabalhou no trimestre.\n- Perguntas objetivas (1-5) + 1 pergunta aberta: "O que essa pessoa deveria continuar fazendo?" e "O que deveria mudar ou desenvolver?"\n- Anonimato garantido: respostas consolidadas pelo gestor antes de compartilhar\n\n**5.3 Semana 2 — Consolidação e Preparação do Feedback**\n\n1. Gestor consolida: autoavaliação + avaliação do gestor + 360°\n2. Calcular nota final ponderada (média com os pesos acima)\n3. Identificar:\n   - **2 pontos fortes** com exemplos específicos (comportamentos observados)\n   - **1-2 pontos de desenvolvimento** com exemplos específicos\n   - **1 ação concreta** para o próximo trimestre (vai para o PDI)\n4. Classificação de performance:\n   - ≥ 4.5: **Alto desempenho** — considerar promoção/aumento\n   - 3.5-4.4: **Sólido** — desenvolvimento focado em maximizar pontos fortes\n   - 2.5-3.4: **Em crescimento** — PDI com acompanhamento quinzenal\n   - < 2.5: **Plano de melhoria** — reunião com Marco/Ruy + prazo de 60 dias\n\n**5.4 Semana 2 — Reunião de Feedback 1:1 (45-60 min)**\n\nEstrutura obrigatória da conversa:\n\n1. **Abertura (5 min)**: contexto, objetivo da conversa, criar clima seguro\n2. **Autoavaliação do colaborador (10 min)**: "Como você avalia seu trimestre?" — ouvir sem interromper\n3. **Feedback do gestor (20 min)**:\n   - Apresentar nota consolidada e como foi calculada\n   - Dois pontos fortes com exemplos concretos (começar pelo positivo)\n   - Pontos de desenvolvimento com exemplos concretos (comportamento, não pessoa)\n   - Perguntar: "Faz sentido para você? Tem alguma parte que vê diferente?"\n4. **Olhar para frente — PDI (15 min)**:\n   - Revisar PDI anterior: o que evoluiu, o que não evoluiu e por quê\n   - Definir 1-3 objetivos de desenvolvimento para o próximo trimestre\n   - Cada objetivo: O QUÊ (comportamento/habilidade) + COMO (ação concreta) + ATÉ QUANDO\n5. **Encerramento (5 min)**: resumo dos compromissos, próximo check-in\n\n**5.5 Pós-avaliação — Decisões e Ações**\n\nDentro de 5 dias úteis após todas as reuniões 1:1:\n1. Marco e Ruy revisam avaliações de líderes de BU\n2. Decisões coletivas:\n   - Promoções ou ajustes salariais (se aplicável)\n   - Realocações de papel ou BU\n   - Planos de melhoria formais (PIP)\n3. PDIs atualizados no TBO OS por todos os colaboradores\n4. Marco comunica ao time as decisões coletivas (sem expor avaliações individuais)\n\n### 6. Checklist de Validação\n\n**Por colaborador avaliado:**\n- [ ] Autoavaliação preenchida dentro do prazo\n- [ ] Avaliação do gestor preenchida\n- [ ] 360° de 2-3 pares coletado\n- [ ] Reunião 1:1 de feedback realizada\n- [ ] PDI atualizado com mínimo 1 objetivo para próximo trimestre\n- [ ] Ações definidas registradas no TBO OS\n\n**Por ciclo completo:**\n- [ ] 100% do time avaliado\n- [ ] Todos os PDIs atualizados\n- [ ] Decisões salariais/promoção comunicadas\n- [ ] Arquivo de avaliações guardado no Drive\n\n### 7. Ferramentas e Recursos\n\n- **TBO OS**: PDI, módulo de avaliação (se disponível), tarefas de desenvolvimento\n- **Google Forms**: formulários de avaliação e 360° (templates na pasta RH)\n- **Google Docs**: template de consolidação de avaliação\n- **Google Drive**: `RH/Avaliações/[ANO]/[TRIMESTRE]/` — arquivos por colaborador\n- **Calendário**: bloco fixo na semana de avaliação para todos os 1:1s\n\n### 8. SLAs e Métricas\n\n| Métrica | Meta |\n|---|---|\n| % do time avaliado por ciclo | 100% |\n| Prazo de autoavaliação preenchida | ≤ 5 dias úteis após abertura |\n| Prazo para reunião 1:1 após consolidação | ≤ 3 dias úteis |\n| % de PDIs atualizados pós-avaliação | 100% |\n| % de colaboradores com ≥ 1 ação de desenvolvimento ativa | 100% |\n| Nota média do time | Acompanhar evolução trimestral |\n\n### 9. Troubleshooting\n\n**Colaborador discorda fortemente da avaliação:**\n→ Ouvir sem defender imediatamente: "Me ajuda a entender o que você vê diferente"\n→ Se o colaborador tem um ponto válido, revisar a nota com abertura\n→ Se não, manter a avaliação com exemplos concretos como suporte\n→ Escalar para Marco se impasse persistir\n\n**Gestor não tem exemplos concretos para o feedback:**\n→ NUNCA dar feedback genérico ("você poderia ser mais proativo")\n→ Se não tem exemplos: adiar a avaliação e observar ativamente por 2 semanas\n→ Dica: manter "diário de evidências" ao longo do trimestre\n\n**Colaborador em plano de melhoria (nota < 2.5):**\n→ Reunião com Marco e Ruy antes do 1:1 com o colaborador\n→ Plano de melhoria formal (PIP) com prazo de 60 dias, metas específicas\n→ Check-ins semanais com o gestor durante o PIP\n→ Se não atingir as metas: processo de desligamento (SOP tbo-rh-004)\n\n**Avaliação de período de experiência (3 meses):**\n→ Mesmo processo, mas com ênfase em adaptação cultural e técnica\n→ Se nota < 3: não efetivação ou extensão de 30 dias do período de experiência\n\n### 10. Template Anexo\n\n**Template: Consolidação de Avaliação Individual**\n```markdown\n# Avaliação de Performance — [Nome do Colaborador]\n**Período:** Q[X] [ANO] | **Avaliador:** [Nome do Gestor]\n**Data da reunião 1:1:** [DD/MM/AAAA]\n\n## Notas por Critério\n| Critério | Peso | Auto | Gestor | 360° | Nota Final |\n|---|---|---|---|---|---|\n| Qualidade de entrega | 25% | | | | |\n| Produtividade e prazo | 20% | | | | |\n| Autonomia e proatividade | 15% | | | | |\n| Colaboração e comunicação | 15% | | | | |\n| Aprendizado e crescimento | 15% | | | | |\n| Alinhamento cultural | 10% | | | | |\n| **TOTAL PONDERADO** | | | | | |\n\n## Classificação: [ ] Alto desempenho / [ ] Sólido / [ ] Em crescimento / [ ] Plano de melhoria\n\n## Pontos Fortes (com exemplos concretos)\n1. \n2. \n\n## Pontos de Desenvolvimento (com exemplos concretos)\n1. \n2. \n\n## PDI — Próximo Trimestre\n| Objetivo | Ação Concreta | Prazo |\n|---|---|---|\n| | | |\n| | | |\n\n## Decisões\n- [ ] Promoção: ___\n- [ ] Ajuste salarial: ___\n- [ ] Realocação: ___\n- [ ] PIP: ___\n- [ ] Nenhuma (manutenção)\n```',
    '',
    'published',
    'high',
    ARRAY['rh', 'performance', 'avaliacao', 'pdi', 'feedback', 'desenvolvimento', 'time'],
    3,
    2
  )
