  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-rh-003-avaliacao-de-performance-e-desenvolvimento';

  DELETE FROM knowledge_sop_steps WHERE sop_id = v_sop_id;

  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index) VALUES
    (v_sop_id, 1, 'Objetivo', E'Gerar crescimento real — não só medir. A avaliação de performance na TBO não é burocracia: é o principal mecanismo de desenvolvimento das pessoas. Cada ciclo deve resultar em 1 ação concreta de desenvolvimento por colaborador. Meta: 100% do time avaliado trimestralmente, 0% sem PDI atualizado.', 'step', 0),
    (v_sop_id, 2, 'Escopo e RACI', E'**Ciclo:** Trimestral (março, junho, setembro, dezembro). Novos colaboradores: ao fim do 3º mês.\n\n| Atividade | Responsável | Aprovador |\n|---|---|---|\n| Disparar ciclo de avaliação | Marco Andolfato | — |\n| Preencher autoavaliação | Colaborador | — |\n| Avaliação do gestor | Líder BU | — |\n| Consolidar 360° | Marco Andolfato | — |\n| Conduzir 1:1 de feedback | Líder BU | — |\n| Atualizar PDI no TBO OS | Colaborador + Líder BU | Marco (líderes) |\n| Decisões salariais/promoção | Marco + Ruy | — |', 'step', 1),
    (v_sop_id, 3, 'Critérios e Escala de Avaliação', E'| Critério | Peso |\n|---|---|\n| Qualidade de entrega | 25% |\n| Produtividade e prazo | 20% |\n| Autonomia e proatividade | 15% |\n| Colaboração e comunicação | 15% |\n| Aprendizado e crescimento | 15% |\n| Alinhamento cultural | 10% |\n\n**Escala 1-5:**\n- **5**: Supera consistentemente\n- **4**: Atende com destaque\n- **3**: Atende o esperado\n- **2**: Em desenvolvimento, precisa de suporte\n- **1**: Abaixo, requer intervenção urgente\n\n**Classificação final:**\n- ≥ 4.5: Alto desempenho (considerar promoção/aumento)\n- 3.5-4.4: Sólido (desenvolver pontos fortes)\n- 2.5-3.4: Em crescimento (PDI com acompanhamento quinzenal)\n- < 2.5: Plano de melhoria (PIP — 60 dias)', 'step', 2),
    (v_sop_id, 4, 'Estrutura do 1:1 de Feedback (45-60 min)', E'1. **Abertura** (5 min): contexto, objetivo, criar clima seguro\n2. **Autoavaliação do colaborador** (10 min): "Como você avalia seu trimestre?" — ouvir sem interromper\n3. **Feedback do gestor** (20 min):\n   - Nota consolidada com explicação do cálculo\n   - 2 pontos fortes com exemplos concretos\n   - 1-2 pontos de desenvolvimento com exemplos concretos\n   - "Faz sentido? Tem algo que você vê diferente?"\n4. **PDI** (15 min): revisar anterior + definir 1-3 objetivos para o próximo trimestre\n5. **Encerramento** (5 min): resumo dos compromissos + próximo check-in', 'step', 3),
    (v_sop_id, 5, 'Checklist de Validação', E'**Por colaborador:**\n- [ ] Autoavaliação preenchida dentro do prazo\n- [ ] Avaliação do gestor preenchida\n- [ ] 360° de 2-3 pares coletado\n- [ ] Reunião 1:1 de feedback realizada\n- [ ] PDI atualizado com ≥ 1 objetivo\n- [ ] Ações registradas no TBO OS\n\n**Por ciclo completo:**\n- [ ] 100% do time avaliado\n- [ ] Todos os PDIs atualizados\n- [ ] Decisões salariais/promoção comunicadas\n- [ ] Arquivo guardado no Drive (`RH/Avaliações/`)', 'checkpoint', 4),
    (v_sop_id, 6, 'SLAs e Métricas', E'| Métrica | Meta |\n|---|---|\n| % do time avaliado por ciclo | 100% |\n| Prazo de autoavaliação | ≤ 5 dias úteis após abertura |\n| Prazo para 1:1 após consolidação | ≤ 3 dias úteis |\n| % de PDIs atualizados | 100% |\n| % com ≥ 1 ação de desenvolvimento ativa | 100% |', 'note', 5),
    (v_sop_id, 7, 'Troubleshooting', E'**Colaborador discorda fortemente da avaliação:**\n→ Ouvir: "Me ajuda a entender o que você vê diferente"\n→ Se ponto válido: revisar nota com abertura\n→ Se não: manter com exemplos concretos como suporte\n→ Escalar para Marco se impasse persistir\n\n**Gestor não tem exemplos concretos:**\n→ NUNCA dar feedback genérico ("seja mais proativo")\n→ Adiar a avaliação e observar ativamente por 2 semanas\n→ Dica: manter diário de evidências ao longo do trimestre\n\n**Nota < 2.5 (plano de melhoria):**\n→ Reunião com Marco e Ruy antes do 1:1\n→ PIP formal com prazo de 60 dias e metas específicas\n→ Check-ins semanais durante o PIP\n→ Se metas não atingidas: processo de desligamento (SOP tbo-rh-004)', 'warning', 6),
    (v_sop_id, 8, 'Template: Consolidação de Avaliação', E'```markdown\n# Avaliação — [Nome] | Q[X] [ANO]\n\n## Notas\n| Critério | Peso | Auto | Gestor | 360° | Final |\n|---|---|---|---|---|---|\n| Qualidade de entrega | 25% | | | | |\n| Produtividade e prazo | 20% | | | | |\n| Autonomia/proatividade | 15% | | | | |\n| Colaboração/comunicação | 15% | | | | |\n| Aprendizado/crescimento | 15% | | | | |\n| Alinhamento cultural | 10% | | | | |\n| **TOTAL PONDERADO** | | | | | |\n\n## Classificação: _________\n\n## Pontos Fortes\n1. \n2. \n\n## Pontos de Desenvolvimento\n1. \n\n## PDI — Próximo Trimestre\n| Objetivo | Ação | Prazo |\n|---|---|---|\n| | | |\n```', 'tip', 7);

  -- ══════════════════════════════════════════════════════════════════════════
  -- MELHORIA 4: Financeiro — Fluxo de Caixa e DRE Mensal
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Fluxo de Caixa e DRE Mensal',
    'tbo-fin-003-fluxo-de-caixa-e-dre-mensal',
    'financeiro',
    'processo',
    'Processo mensal de fechamento financeiro da TBO: apuração de receitas e despesas, elaboração do DRE (Demonstração do Resultado do Exercício), análise de fluxo de caixa e apresentação à diretoria. Ciclo 15-15 (fechamento do dia 15 ao dia 15 do mês seguinte).',
    E'## Fluxo de Caixa e DRE Mensal\n\n### 1. Objetivo\nGerar visibilidade financeira completa para a diretoria da TBO até o dia 20 de cada mês. O DRE e o fluxo de caixa são os principais instrumentos de gestão financeira: revelam a saúde do negócio, identificam desvios de rentabilidade por BU e subsidiam decisões de contratação, investimento e pricing. Meta: DRE fechado e apresentado à diretoria até D+5 após o encerramento do ciclo (dia 20 de cada mês).\n\n### 2. Escopo\n**Quem executa:** Responsável Financeiro (operação) + Marco Andolfato e Ruy Lima (revisão e apresentação)\n**Ciclo financeiro TBO:** Dia 15 do mês corrente ao dia 14 do mês seguinte (ciclo 15-15)\n**Quando se aplica:** Todo mês, sem exceção\n**Limites:** Faturamento → SOP tbo-fin-001. Contas a pagar → SOP tbo-fin-002. Conciliação bancária → SOP tbo-fin-004. Budget anual → SOP tbo-fin-006.\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Lançar receitas do período | Resp. Financeiro | — | — | — |\n| Lançar despesas por CC (centro de custo) | Resp. Financeiro | — | Líderes BU | — |\n| Conciliar contas bancárias | Resp. Financeiro | Marco Andolfato | — | — |\n| Apurar resultado por BU | Resp. Financeiro | Marco Andolfato | — | — |\n| Elaborar DRE consolidado | Resp. Financeiro | Marco Andolfato | — | — |\n| Elaborar análise de fluxo de caixa | Resp. Financeiro | Marco Andolfato | — | — |\n| Apresentar DRE à diretoria | Marco Andolfato | — | Ruy Lima | — |\n| Tomar decisões pós-DRE | Marco + Ruy | — | — | Líderes BU |\n| Arquivar DRE no Drive | Resp. Financeiro | — | — | — |\n\n### 4. Pré-requisitos\n\n- [ ] Todos os lançamentos de receita do período inseridos (faturas pagas)\n- [ ] Todas as despesas lançadas com centro de custo correto (BU + natureza)\n- [ ] Extrato bancário do mês disponível para conciliação\n- [ ] Folha de pagamento processada e lançada\n- [ ] Notas fiscais de fornecedores recebidas e lançadas\n- [ ] Planilha de DRE com estrutura padrão disponível\n\n### 5. Procedimento\n\n**5.1 Centros de Custo (CCs) — Estrutura Padrão da TBO**\n\n| Código | BU | Exemplos de lançamento |\n|---|---|---|\n| BRD | Branding | Freelancers de design, impressão, softwares |\n| D3D | Digital 3D | Licenças 3D, render farm, hardware |\n| MKT | Marketing | Mídia paga, ferramentas de marketing, conteúdo |\n| AV | Audiovisual | Equipamentos, aluguel de locação, pós-produção |\n| INT | Interiores | Materiais, visitas técnicas, freelancers |\n| ADM | Administrativo | Aluguel, contas de consumo, seguros, contador |\n| CORP | Corporativo | Salários diretoria, viagens estratégicas, eventos |\n\n**5.2 Dias 15-20 — Fechamento e Lançamentos**\n\n1. **Dia 15**: abertura do novo ciclo\n   - Verificar faturas vencidas e pagas no período anterior\n   - Confirmar recebimento de todas as parcelas previstas\n   - Checar inadimplência: faturas vencidas há mais de 5 dias (SOP tbo-fin-005)\n\n2. **Dias 15-18**: lançamento completo\n   - Lançar todas as receitas: faturas pagas, adiantamentos recebidos, reembolsos\n   - Lançar todas as despesas: fornecedores, folha, impostos, despesas fixas e variáveis\n   - Classificar cada despesa por CC + natureza (pessoal, serviços, infraestrutura, marketing)\n   - Verificar pendências: despesas incorridas mas ainda sem NF (provisionar)\n\n3. **Dia 18-19**: conciliação bancária\n   - Baixar extrato bancário de todas as contas\n   - Conciliar cada transação com os lançamentos na planilha\n   - Identificar lançamentos sem correspondência no extrato\n   - Resolver discrepâncias antes de fechar\n\n**5.3 Dia 19-20 — Elaboração do DRE**\n\n**Estrutura do DRE TBO:**\n\n```\nRECEITA BRUTA\n(-) Impostos sobre serviços (ISS, PIS, COFINS)\n= RECEITA LÍQUIDA\n\n(-) CUSTO DOS SERVIÇOS PRESTADOS (CSP)\n   Pessoal direto (equipe de produção)\n   Freelancers e terceiros\n   Softwares e licenças de produção\n   Materiais e insumos de produção\n= LUCRO BRUTO\n\n(-) DESPESAS OPERACIONAIS\n   Pessoal administrativo/diretoria\n   Aluguel e infraestrutura\n   Marketing e prospecção\n   Tecnologia e ferramentas\n   Financeiras (tarifas bancárias, juros)\n   Outras despesas gerais\n= EBITDA\n\n(-) Depreciação e amortização\n= EBIT (Lucro Operacional)\n\n(-) Resultado financeiro líquido\n= LUCRO ANTES DO IR\n\n(-) Imposto de Renda / Contribuição Social\n= LUCRO LÍQUIDO\n```\n\n**Por BU (análise de rentabilidade):**\n- Receita de cada BU no período\n- Custos diretos alocados por CC\n- Margem bruta por BU\n- % de receita e margem por BU vs. total TBO\n\n**5.4 Dia 20 — Análise de Fluxo de Caixa**\n\n1. **Posição de caixa atual**: saldo em conta + aplicações\n2. **Entradas previstas próximos 30 dias**: parcelas a receber confirmadas\n3. **Saídas previstas próximos 30 dias**: vencimentos de fornecedores + folha\n4. **Saldo projetado ao fim do mês**: caixa atual + entradas - saídas\n5. **Caixa mínimo operacional TBO**: equivalente a 2 meses de despesas fixas\n6. **Alertas**: se projeção < caixa mínimo → escalar imediatamente para Marco/Ruy\n\n**5.5 Dia 20 — Apresentação à Diretoria**\n\nReunião mensal de 60 min (Marco + Ruy):\n\n1. **Resultado do mês** (20 min):\n   - DRE consolidado: receita, custos, margens\n   - Comparativo vs. mês anterior e vs. budget\n   - Resultado por BU (ranking de rentabilidade)\n\n2. **Fluxo de caixa** (15 min):\n   - Posição atual + projeção 30 dias\n   - Inadimplências relevantes\n   - Pagamentos pendentes relevantes\n\n3. **Análise de desvios** (15 min):\n   - O que foi diferente do esperado e por quê?\n   - Receita acima/abaixo: novos projetos, cancelamentos, atrasos?\n   - Despesa acima/abaixo: extra-ordinários, economias, erros de provisão?\n\n4. **Decisões e ações** (10 min):\n   - Ajustes de pricing ou mix de projetos?\n   - Contenção de despesas necessária?\n   - Investimentos aprovados para o próximo período?\n\n### 6. Checklist de Validação\n\n**Antes de fechar o DRE:**\n- [ ] Todas as receitas do período lançadas e conciliadas com extrato\n- [ ] Todas as despesas lançadas com CC e natureza corretos\n- [ ] Folha de pagamento lançada\n- [ ] Impostos calculados e lançados\n- [ ] Conciliação bancária 100% (zero diferença)\n- [ ] Provisões de despesas incorridas sem NF lançadas\n\n**Antes da apresentação à diretoria:**\n- [ ] DRE revisado e aprovado pelo responsável financeiro\n- [ ] Comparativo vs. mês anterior calculado\n- [ ] Comparativo vs. budget calculado (se disponível)\n- [ ] Fluxo de caixa projetado para 30 dias\n- [ ] Desvios relevantes explicados com contexto\n- [ ] Arquivo salvo no Drive (`Financeiro/DRE/[ANO]/`)\n\n### 7. Ferramentas e Recursos\n\n- **TBO OS (módulo financeiro)**: lançamentos, centros de custo, fluxo de caixa\n- **Planilha de DRE** (Google Sheets): `Financeiro/DRE/template-dre-tbo.xlsx`\n- **Extrato bancário**: download direto do internet banking\n- **Sistema de NFs**: emissão e controle de notas fiscais\n- **Google Drive**: `Financeiro/DRE/[ANO]/DRE-[MES]-[ANO].pdf`\n\n### 8. SLAs e Métricas\n\n| Métrica | Meta |\n|---|---|\n| DRE fechado e apresentado à diretoria | ≤ Dia 20 do mês |\n| Conciliação bancária com 0 diferença | 100% dos meses |\n| Lançamentos sem CC correto | 0% |\n| DRE arquivado no Drive | 100% dos meses |\n| Margem EBITDA TBO | Acompanhar — meta: ≥ 20% |\n| Caixa mínimo operacional mantido | ≥ 2 meses de despesas fixas |\n\n### 9. Troubleshooting\n\n**Discrepância na conciliação bancária:**\n→ Identificar a transação sem correspondência\n→ Verificar se é lançamento esquecido ou erro de data\n→ NUNCA fechar DRE com conciliação pendente\n→ Se não resolver em 24h: acionar contador\n\n**Despesa sem CC definido:**\n→ Retornar para quem fez o lançamento para classificar\n→ Se não identificado: provisoriamente em ADM com nota de revisão\n→ Criar controle: toda despesa > R$200 requer CC obrigatório no TBO OS\n\n**Receita de projeto aberta (faturada mas não recebida):**\n→ Registrar como "a receber" (não como receita realizada)\n→ Verificar inadimplência (SOP tbo-fin-005)\n→ Apresentar no DRE como dedutor de caixa projetado\n\n**Projeção de caixa abaixo do mínimo operacional:**\n→ Alertar Marco e Ruy imediatamente (não esperar a reunião do dia 20)\n→ Mapear entradas confirmadas para os próximos 15 dias\n→ Acionar cobrança acelerada de inadimplentes prioritários\n→ Segurar pagamentos não urgentes a fornecedores\n\n### 10. Template Anexo\n\n**Template: DRE Mensal TBO (Google Sheets)**\n```markdown\n# DRE — [MÊS] [ANO] | TBO\n\n## Resultado Consolidado\n| | R$ | % Receita Líquida | vs. Mês Ant. | vs. Budget |\n|---|---|---|---|---|\n| Receita Bruta | | | | |\n| (-) Impostos | | | | |\n| = Receita Líquida | | | | |\n| (-) CSP | | | | |\n| = Lucro Bruto | | | | |\n| Margem Bruta | | | | |\n| (-) Despesas Operacionais | | | | |\n| = EBITDA | | | | |\n| Margem EBITDA | | | | |\n| = Lucro Líquido | | | | |\n| Margem Líquida | | | | |\n\n## Resultado por BU\n| BU | Receita | Custo Direto | Margem Bruta | % Margem |\n|---|---|---|---|---|\n| BRD | | | | |\n| D3D | | | | |\n| MKT | | | | |\n| AV | | | | |\n| CORP/ADM | | | | |\n| **TOTAL** | | | | |\n\n## Fluxo de Caixa — Projeção 30 dias\n- **Caixa atual:** R$ ___\n- **Entradas confirmadas:** R$ ___\n- **Saídas previstas:** R$ ___\n- **Saldo projetado:** R$ ___\n- **Caixa mínimo operacional:** R$ ___\n- **Status:** [ ] OK / [ ] ALERTA / [ ] CRÍTICO\n\n## Desvios Relevantes\n1. \n2. \n\n## Decisões da Diretoria\n| Decisão | Responsável | Prazo |\n|---|---|---|\n| | | |\n```',
    '',
